def solve_m_coloring(graph, m):
    V = len(graph)
    colors = [0] * V

    def is_safe(v_idx, color):
        for i in range(V):
            if graph[v_idx][i] == 1 and colors[i] == color:
                return False
        return True

    def graph_color_util(v_idx):
        if v_idx == V:
            return True

        for c in range(1, m + 1):
            if is_safe(v_idx, c):
                colors[v_idx] = c
                if graph_color_util(v_idx + 1):
                    return True
                colors[v_idx] = 0
        return False

    if not graph_color_util(0):
        return []
    return colors
